class Solution(object):
    def buildTree(self, inorder, postorder):
        inorder_map = {v: i for i, v in enumerate(inorder)}
        def build(in_left, in_right, post_left, post_right):
            if in_left > in_right:
                return None
            root_val = postorder[post_right]
            root = TreeNode(root_val)
            root_idx = inorder_map[root_val]
            left_size = root_idx - in_left
            root.left = build(in_left, root_idx - 1, post_left, post_left + left_size - 1)
            root.right = build(root_idx + 1, in_right, post_left + left_size, post_right - 1)
            return root
        return build(0, len(inorder) - 1, 0, len(postorder) - 1)
